var CountIntervals = function() {
    this.spans = [];
    this.total = 0;
};
CountIntervals.prototype.add = function(left, right) {
    let newLeft = left, newRight = right;
    const kept = [];
    for (const [lo, hi] of this.spans) {
        if (hi < newLeft - 1 || lo > newRight + 1) {
            kept.push([lo, hi]);
        } else {
            this.total -= (hi - lo + 1);
            newLeft = Math.min(newLeft, lo);
            newRight = Math.max(newRight, hi);
        }
    }
    kept.push([newLeft, newRight]);
    this.total += (newRight - newLeft + 1);
    this.spans = kept;
    return null;
};
CountIntervals.prototype.count = function() {
    return this.total;
};
